import express from 'express';
import { usersRouter } from './routes/users.js';
import { productsRouter } from './routes/products.js';
import { errorHandler } from './middleware/error-handler.js';

const app = express();
app.use(express.json());
app.use('/api/users', usersRouter);
app.use('/api/products', productsRouter);
app.use(errorHandler);

export { app };

import { Router } from 'express';
import { authenticate } from '../middleware/auth.js';
import { UserModel } from '../models/user.js';
import { AppError } from '../types/index.js';

export const usersRouter = Router();

usersRouter.get('/', authenticate, async (req, res, next) => {
  try {
    const users = await UserModel.findAll({ limit: 50 });
    res.json({ data: users, total: users.length });
  } catch (err) { next(err); }
});

usersRouter.get('/:id', authenticate, async (req, res, next) => {
  try {
    const user = await UserModel.findById(req.params.id);
    if (!user) throw new AppError(404, 'User not found');
    res.json({ data: user });
  } catch (err) { next(err); }
});

import { Request, Response, NextFunction } from 'express';
import { AppError } from '../types/index.js';

export function authenticate(req: Request, res: Response, next: NextFunction): void {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) throw new AppError(401, 'No token provided');
  // JWT verification would go here
  next();
}

